let shuttingDown = false;
const children = [backend, web];

for (const signal of ['SIGINT', 'SIGTERM']) {
  process.on(signal, () => shutdown(signal));
}

for (const child of children) {
  child.on('exit', (code, signal) => {
    if (shuttingDown) {
