import type { Meta, StoryObj } from '@storybook/tanstack-react';
import { expect, fn, userEvent } from 'storybook/test';

import { SessionWorkspacePanel } from '@/features/home/components/organisms/session-workspace-panel';
import { emptyKanbanColumns } from '@/features/home/demo/session-workspace.fixtures';

const meta = {
  title: 'Home/Session Workspace Panel',
  component: SessionWorkspacePanel,
  parameters: {
    layout: 'fullscreen',
  },
  decorators: [
    (Story) => (
      <div className="h-[640px] bg-background font-mono text-foreground">
        <Story />
      </div>
    ),
  ],
} satisfies Meta<typeof SessionWorkspacePanel>;

export default meta;

type Story = StoryObj<typeof meta>;

const baseArgs = {
  kanbanColumns: emptyKanbanColumns,
  onWorkerSessionSelect: () => {},
  selectedTerminalSession: undefined,
} satisfies Partial<Story['args']>;

export const EmptyKanban: Story = {
  args: {
    ...baseArgs,
    onWorkspaceRefresh: fn(),
    view: 'kanban',
    workspaceState: 'empty',
  },
  play: async ({ args, canvas }) => {
    await expect(
      canvas.getByRole('heading', { name: 'No AO workers detected' })
    ).toBeVisible();

    await userEvent.click(canvas.getByRole('button', { name: 'Refresh' }));
    await expect(args.onWorkspaceRefresh).toHaveBeenCalled();
  },
};

export const EmptyTerminal: Story = {
  args: {
    ...baseArgs,
    onWorkspaceRefresh: fn(),
    view: 'terminal',
    workspaceState: 'empty',
  },
  play: async ({ args, canvas }) => {
    await expect(
      canvas.getByRole('heading', { name: 'No AO workers detected' })
    ).toBeVisible();

    await userEvent.click(canvas.getByRole('button', { name: 'Refresh' }));
    await expect(args.onWorkspaceRefresh).toHaveBeenCalled();
  },
};

export const Loading: Story = {
  args: {
    ...baseArgs,
    onWorkspaceRefresh: () => {},
    view: 'kanban',
    workspaceState: 'loading',
  },
  play: async ({ canvas }) => {
    await expect(
      canvas.getByRole('heading', { name: 'Loading AO workspace' })
    ).toBeVisible();
    await expect(
      canvas.queryByRole('button', { name: 'Refresh' })
    ).not.toBeInTheDocument();
  },
};

export const ErrorState: Story = {
  args: {
    ...baseArgs,
    onWorkspaceRefresh: fn(),
    view: 'kanban',
    workspaceError: 'The local AO runtime is not responding.',
    workspaceState: 'error',
  },
  play: async ({ args, canvas }) => {
    await expect(
      canvas.getByRole('heading', { name: 'Workspace unavailable' })
    ).toBeVisible();
    await expect(
      canvas.getByText('The local AO runtime is not responding.')
    ).toBeVisible();

    await userEvent.click(canvas.getByRole('button', { name: 'Refresh' }));
    await expect(args.onWorkspaceRefresh).toHaveBeenCalled();
  },
};
